+            available: 512,
+        };
+        assert!(err.to_string().contains("1024"));
+        assert!(err.to_string().contains("512"));
+    }
+
+    #[test]
+    fn test_error_variants() {
+        let err = ContainerError::EpochExhausted {
+            used: 100,
+            budget: 50,
+        };
