+            reason: "bad value".into(),
+        };
+        assert!(err.to_string().contains("bad value"));
+
+        let err = ContainerError::NotInitialized;
+        assert!(err.to_string().contains("not initialized"));
+
+        let err = ContainerError::SlabOverflow {
+            component: "graph".into(),
+        };
