+            let row_sum: f64 = lap.values[s..e].iter().sum();
+            assert!(row_sum.abs() < 1e-10, "Row {} sum = {}", i, row_sum);
+            let diag = (s..e).find(|&j| lap.col_indices[j] == i).map(|j| lap.values[j]).unwrap();
+            assert!((diag - 2.0).abs() < 1e-10, "Diag[{}] = {}", i, diag);
