+    #[test]
+    fn test_cold_tier_ewc() {
+        let tmp = TempDir::new().unwrap();
+        let ewc_dir = tmp.path().join("ewc");
+
+        let dim = 4;
+        let num_params = 3;
+        let lambda = 100.0;
+
+        let mut ewc = ColdTierEwc::new(&ewc_dir, dim, num_params, lambda).unwrap();
+
+        // Compute Fisher from gradients (1 sample, 3 param rows)
+        let gradients = vec![
+            vec![1.0, 2.0, 3.0, 4.0],
+            vec![0.5, 0.5, 0.5, 0.5],
+            vec![2.0, 1.0, 0.0, 1.0],
