+        let penalty = ewc.penalty(&deviated).unwrap();
+        assert!(penalty > 0.0);
+
+        // Gradient for param 0 should be lambda * fisher * diff
+        let grad = ewc.gradient(&deviated, 0).unwrap();
+        assert!((grad[0] - 100.0 * 1.0 * 1.0).abs() < 1e-4);
+        assert!((grad[1] - 100.0 * 4.0 * 1.0).abs() < 1e-4);
+    }
