+    assert_eq!(true_value, 1.0);
+
+    let result = canonical.canonical_cut();
+    assert!(
+        (result.value - true_value).abs() < 1e-9,
+        "Canonical value {} != true min-cut {}",
+        result.value,
+        true_value
+    );
+}
